const MOOD_DICT = {
  joyful: ['love','loved','amazing','awesome','incredible','wonderful','delighted','happy','thrilled','excited','fun','joy','magical','beautiful','gorgeous','fantastic','perfect','best','favorite','favourite','smile','laughed','laugh','celebrated','celebration'],
  triumphant: ['proud','shipped','launched','nailed','crushed','delivered','finished','completed','succeeded','achieved','accomplished','won','victory','breakthrough','milestone','hit','landed','dominated','smashed','knocked'],
  thoughtful: ['realized','realised','learned','understood','discovered','reflected','noticed','wondered','figured','insight','clarity','perspective','listened','patience','slowly','quiet','deep'],
  challenging: ['hard','tough','difficult','struggled','struggle','failed','failure','overwhelmed','stressed','stressful','exhausted','burnout','burned out','tired','frustrated','frustration','confused','stuck','lost','doubt','anxious','anxiety','worry','worried','pain','painful','scared'],
  warm: ['team','together','friend','friends','colleague','partner','helped','help','support','supported','kind','kindness','generous','shared','sharing','community','grateful','gratitude','appreciate','thankful','trust','trusted','care','cared'],
  growth: ['grew','growth','growing','changed','change','new','first','stretched','challenged myself','pushed','learned how','became','transformed','evolved','opened up','stepped up','tried'],
};

function detectMood(text) {
  if (!text || typeof text !== 'string') return 'neutral';
  const t = text.toLowerCase();
  const scores = {};
  for (const [mood, words] of Object.entries(MOOD_DICT)) {
    scores[mood] = words.reduce((n, w) => n + (t.includes(w) ? 1 : 0), 0);
  }
  const entries = Object.entries(scores).sort((a, b) => b[1] - a[1]);
  if (!entries[0] || entries[0][1] === 0) return 'neutral';
  if (entries[0][0] === 'challenging' && scores.growth >= scores.challenging - 1 && scores.growth > 0) {
    return 'growth';
  }
  return entries[0][0];
}

