function MoodField({ palette, slideIndex }) {
  if (slideIndex === 0) {
    return (
      <div className="absolute inset-0 pointer-events-none z-0 overflow-hidden">
        <div className="absolute" style={{ top: '18%', left: '7%', width: 56, height: 56, border: `2px solid ${palette.accent}`, borderRadius: '50%', opacity: 0.55, animation: 'softFloat 9s ease-in-out infinite' }} />
        <div className="absolute" style={{ bottom: '15%', right: '8%', width: 72, height: 72, background: palette.accent, opacity: 0.35, animation: 'slowBlob 14s ease-in-out infinite, softFloat2 11s ease-in-out infinite' }} />
      </div>
    );
  }

  const seed = slideIndex * 13 + 7;
  const rand = (i) => {
    const x = Math.sin(seed * 9999 + i * 113) * 10000;
    return x - Math.floor(x);
  };

  const particles = palette.particles || [];
  const count = 18;
  const items = [];
  for (let i = 0; i < count; i++) {
    const emoji = particles[i % particles.length];
    const top = `${6 + rand(i) * 86}%`;
    const left = `${4 + rand(i + 100) * 90}%`;
    const size = 16 + Math.floor(rand(i + 200) * 30);
    const delay = `${rand(i + 300) * 4}s`;
    const duration = `${8 + rand(i + 400) * 10}s`;
    const anim = ['softFloat','softFloat2','gentleDrift','twinkle','swayGentle'][i % 5];
    const opacity = 0.55 + rand(i + 500) * 0.45;
    items.push(
      <div
        key={i}
        style={{
          position: 'absolute',
          top, left,
          fontSize: size,
          opacity,
          lineHeight: 1,
          animation: `${anim} ${duration} ease-in-out ${delay} infinite`,
          fontFamily: "'Syne', sans-serif",
          color: /\p{Emoji}/u.test(emoji) ? 'inherit' : palette.accent,
          fontWeight: 700,
          userSelect: 'none',
        }}
      >
        {emoji}
      </div>
    );
  }

  return <div className="absolute inset-0 pointer-events-none z-0 overflow-hidden">{items}</div>;
}

