function Shape({ kind, color, size, top, left, anim, opacity = 1 }) {
  const base = { position: 'absolute', top, left, width: size, height: size, opacity, animation: anim };
  if (kind === 'circle-outline') return <div style={{ ...base, border: `2px solid ${color}`, borderRadius: '50%' }} />;
  if (kind === 'square') return <div style={{ ...base, background: color }} />;
  if (kind === 'triangle') return <svg viewBox="0 0 40 40" style={base}><polygon points="20,4 4,36 36,36" fill={color} /></svg>;
  if (kind === 'blob') return <div style={{ ...base, background: color, borderRadius: '60% 40% 30% 70% / 60% 30% 70% 40%' }} />;
  if (kind === 'star') return <div style={{ ...base, color, fontFamily: "'Syne', sans-serif", fontWeight: 800, fontSize: size, lineHeight: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>✦</div>;
  return null;
}

function Confetti() {
  const pieces = Array.from({ length: 24 });
  const shapes = ['square', 'circle', 'triangle', 'star'];
  const colors = [CORAL, LEMON, INK];
  return (
    <div className="pointer-events-none fixed inset-0 z-50 overflow-hidden">
      {pieces.map((_, i) => {
        const left = Math.random() * 100;
        const delay = Math.random() * 0.4;
        const duration = 2.2 + Math.random() * 1.6;
        const size = 10 + Math.random() * 14;
        const drift = (Math.random() - 0.5) * 160;
        const rot = 360 + Math.random() * 540;
        const kind = shapes[i % shapes.length];
        const color = colors[i % colors.length];
        const common = {
          position: 'absolute',
          left: `${left}%`,
          top: 0,
          width: size,
          height: size,
          '--drift': `${drift}px`,
          '--rot': `${rot}deg`,
          animation: `confettiFall ${duration}s ease-in ${delay}s forwards`,
        };
        if (kind === 'square') return <div key={i} style={{ ...common, background: color }} />;
        if (kind === 'circle') return <div key={i} style={{ ...common, background: color, borderRadius: '50%' }} />;
        if (kind === 'triangle') return <svg key={i} viewBox="0 0 40 40" style={common}><polygon points="20,4 4,36 36,36" fill={color} /></svg>;
        if (kind === 'star') return <div key={i} style={{ ...common, color, fontFamily: "'Syne', sans-serif", fontWeight: 800, fontSize: size * 1.4, lineHeight: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>✦</div>;
        return null;
      })}
    </div>
  );
}

function buildSummary(d, firstName) {
  const line = '─────────────────────────────────────';
  return `XD COOLDOWN — ${firstName.toUpperCase()}'S TAX SEASON 2026, WRAPPED
${line}
For: future ${firstName}, January 1, 2027


01 / PEAK MOMENT
${d.high}


02 / A MOMENT THAT STUCK
${d.memorable}


03 / WHAT I LEARNED
${d.lesson}


04 / SOMEONE TO THANK
${d.shoutoutName}
"${d.shoutoutMessage}"


05 / MY WORD FOR 2027
${(d.word || '').toUpperCase()}


06 / A LETTER TO JANUARY 2027 ME
${d.capsule}


${line}
Sealed at the XD Cooldown, end of tax season 2026.
`;
}
